select * from product
         where product_name = #{productName}
limit 1

select id from product where product_name = #{productName}
order by created_time desc
limit 1

SELECT p.id, p.product_name as productName FROM product p INNER JOIN ( SELECT product_name, MAX(created_time) as max_time FROM product WHERE product_name IN
#{name}
GROUP BY product_name ) latest ON p.product_name = latest.product_name AND p.created_time = latest.max_time

